const pptxgen = require("pptxgenjs");

const pres = new pptxgen();
pres.layout = "LAYOUT_WIDE"; // 13.3 x 7.5
pres.author = "Amine Cheikhrouhou";
pres.title = "Cross-Modal Content-Based Retrieval for 3D Medical Images";

// ---- Palette (MRI-viewer dark, teal accent) ----
const NAVY = "0B1F2A";      // deep background
const NAVY2 = "12303F";     // panel
const TEAL = "14B8A6";      // accent
const MINT = "5EEAD4";      // bright accent
const LIGHT = "F7FAFB";     // content bg
const INK = "0F2230";       // dark text on light
const MUTED = "5B7488";     // muted text
const CARD = "FFFFFF";
const AMBER = "F59E0B";     // attention accent

const FONT_H = "Cambria";
const FONT_B = "Calibri";

const W = 13.333, H = 7.5;

const IMG_D2 = "D:/Projects/Hackathons/EHL_Hackathon_Cross-modal_Content-based_Retrieval_for_3D_Medical_Images/ehl-paris-2026-medical-retrieval-main/ehl-paris-2026-medical-retrieval-main/assets/dataset2_example_pair.png";
const IMG_D3 = "D:/Projects/Hackathons/EHL_Hackathon_Cross-modal_Content-based_Retrieval_for_3D_Medical_Images/ehl-paris-2026-medical-retrieval-main/ehl-paris-2026-medical-retrieval-main/assets/dataset3_example_pair.png";

const shadow = () => ({ type: "outer", color: "000000", blur: 7, offset: 3, angle: 90, opacity: 0.18 });

function header(slide, kicker, title) {
  slide.background = { color: LIGHT };
  slide.addText(kicker.toUpperCase(), { x: 0.6, y: 0.42, w: 11, h: 0.3, fontFace: FONT_B, fontSize: 12, bold: true, color: TEAL, charSpacing: 3, margin: 0 });
  slide.addText(title, { x: 0.6, y: 0.7, w: 12.1, h: 0.75, fontFace: FONT_H, fontSize: 30, bold: true, color: INK, margin: 0 });
}

// ============================================================
// Slide 1 — Title
// ============================================================
let s = pres.addSlide();
s.background = { color: NAVY };
// faint motif circles (brain/scan rings)
s.addShape(pres.shapes.OVAL, { x: 9.7, y: -1.6, w: 5.4, h: 5.4, fill: { color: TEAL, transparency: 88 }, line: { type: "none" } });
s.addShape(pres.shapes.OVAL, { x: 10.7, y: -0.6, w: 3.4, h: 3.4, fill: { color: TEAL, transparency: 80 }, line: { type: "none" } });
s.addShape(pres.shapes.OVAL, { x: -1.4, y: 4.6, w: 4.6, h: 4.6, fill: { color: MINT, transparency: 90 }, line: { type: "none" } });

s.addText("EHL PARIS 2026  ·  INRIA  ·  KAGGLE CHALLENGE", { x: 0.7, y: 0.85, w: 11, h: 0.3, fontFace: FONT_B, fontSize: 13, bold: true, color: MINT, charSpacing: 3, margin: 0 });
s.addText("Cross-Modal Retrieval for\n3D Medical Images", { x: 0.7, y: 1.7, w: 11.5, h: 2.0, fontFace: FONT_H, fontSize: 50, bold: true, color: "FFFFFF", lineSpacingMultiple: 1.0, margin: 0 });
s.addText("Matching the same patient across MRI contrasts — no training, no labels, no leak.", { x: 0.72, y: 3.75, w: 10.5, h: 0.5, fontFace: FONT_B, fontSize: 18, italic: true, color: "C9DCE5", margin: 0 });

// score callout pill
s.addShape(pres.shapes.ROUNDED_RECTANGLE, { x: 0.7, y: 4.7, w: 3.5, h: 1.55, fill: { color: NAVY2 }, line: { color: TEAL, width: 1 }, rectRadius: 0.12, shadow: shadow() });
s.addText("0.703", { x: 0.7, y: 4.82, w: 3.5, h: 0.85, fontFace: FONT_H, fontSize: 46, bold: true, color: MINT, align: "center", margin: 0 });
s.addText("MACRO MRR  ·  from 0.455 baseline", { x: 0.7, y: 5.72, w: 3.5, h: 0.35, fontFace: FONT_B, fontSize: 11, bold: true, color: "9FB8C4", align: "center", charSpacing: 1, margin: 0 });

s.addText("Amine Cheikhrouhou", { x: 0.72, y: 6.75, w: 8, h: 0.35, fontFace: FONT_B, fontSize: 14, color: "C9DCE5", margin: 0 });

// ============================================================
// Slide 2 — The problem
// ============================================================
s = pres.addSlide();
header(s, "The task", "Find the same patient — across imaging modalities");
// left text
s.addText([
  { text: "Given a query ", options: {} },
  { text: "contrast-T1 (ceT1)", options: { bold: true, color: TEAL } },
  { text: " brain scan, rank a gallery of ", options: {} },
  { text: "T2", options: { bold: true, color: TEAL } },
  { text: " scans so the ", options: {} },
  { text: "same individual's", options: { bold: true } },
  { text: " T2 sits at rank 1.", options: {} },
], { x: 0.6, y: 1.75, w: 5.6, h: 1.3, fontFace: FONT_B, fontSize: 18, color: INK, lineSpacingMultiple: 1.12, margin: 0 });

const why = [
  ["Modality gap", "ceT1 and T2 show the same anatomy with inverted, non-linear intensities."],
  ["Geometry gap", "Volumes are independently positioned, scaled, even deformed."],
  ["No identity labels", "It is retrieval, not classification — and the patients are unseen."],
];
let yy = 3.2;
why.forEach(([t, d]) => {
  s.addShape(pres.shapes.OVAL, { x: 0.6, y: yy + 0.04, w: 0.16, h: 0.16, fill: { color: TEAL }, line: { type: "none" } });
  s.addText([
    { text: t + "  —  ", options: { bold: true, color: INK } },
    { text: d, options: { color: MUTED } },
  ], { x: 0.95, y: yy - 0.12, w: 5.3, h: 0.6, fontFace: FONT_B, fontSize: 14, margin: 0, valign: "top" });
  yy += 0.82;
});

s.addText([
  { text: "Metric:  ", options: { bold: true, color: AMBER } },
  { text: "mean reciprocal rank, averaged over 3 datasets.", options: { color: INK } },
], { x: 0.6, y: 5.95, w: 5.7, h: 0.5, fontFace: FONT_B, fontSize: 14, margin: 0 });

// right: MRI pair on dark panel
s.addShape(pres.shapes.ROUNDED_RECTANGLE, { x: 6.7, y: 1.7, w: 6.05, h: 4.75, fill: { color: NAVY }, line: { type: "none" }, rectRadius: 0.1, shadow: shadow() });
s.addImage({ path: IMG_D2, x: 6.95, y: 2.35, w: 5.55, h: 3.05, sizing: { type: "contain", w: 5.55, h: 3.05 } });
s.addText("Same patient, same axial slice.", { x: 6.95, y: 5.5, w: 5.55, h: 0.35, fontFace: FONT_B, fontSize: 14, bold: true, color: "FFFFFF", align: "center", margin: 0 });
s.addText("The retrieval engine must see through the contrast.", { x: 6.95, y: 5.85, w: 5.55, h: 0.35, fontFace: FONT_B, fontSize: 12, italic: true, color: "9FB8C4", align: "center", margin: 0 });
s.addText("Query  ·  ceT1", { x: 6.95, y: 2.05, w: 2.7, h: 0.3, fontFace: FONT_B, fontSize: 11, bold: true, color: MINT, align: "center", margin: 0 });
s.addText("Target  ·  T2", { x: 9.8, y: 2.05, w: 2.7, h: 0.3, fontFace: FONT_B, fontSize: 11, bold: true, color: MINT, align: "center", margin: 0 });

// ============================================================
// Slide 3 — Three datasets, rising difficulty
// ============================================================
s = pres.addSlide();
header(s, "The landscape", "One problem, three difficulty regimes");

const ds = [
  ["D1", "Aligned", "Pairs share a common voxel grid (BraTS-format). Solvable by direct image comparison.", TEAL, "0.72"],
  ["D2", "Deformed", "D1 + independent rigid & non-linear deformation. Needs geometry-invariant matching.", AMBER, "≈0.60"],
  ["D3", "Pre → intra-op", "Structurally different anatomy (resection). The hardest — shape is the signal.", "EF6C6C", "0.85"],
];
const cx = [0.6, 4.87, 9.14];
ds.forEach(([tag, name, desc, col, mrr], i) => {
  const x = cx[i];
  s.addShape(pres.shapes.ROUNDED_RECTANGLE, { x, y: 1.85, w: 3.6, h: 4.55, fill: { color: CARD }, line: { color: "E3EAEE", width: 1 }, rectRadius: 0.08, shadow: shadow() });
  s.addShape(pres.shapes.ROUNDED_RECTANGLE, { x: x + 0.35, y: 2.25, w: 1.0, h: 1.0, fill: { color: col }, line: { type: "none" }, rectRadius: 0.5 });
  s.addText(tag, { x: x + 0.35, y: 2.25, w: 1.0, h: 1.0, fontFace: FONT_H, fontSize: 26, bold: true, color: "FFFFFF", align: "center", valign: "middle", margin: 0 });
  s.addText(name, { x: x + 1.5, y: 2.45, w: 2.0, h: 0.6, fontFace: FONT_H, fontSize: 21, bold: true, color: INK, valign: "middle", margin: 0 });
  s.addText(desc, { x: x + 0.35, y: 3.55, w: 2.95, h: 1.7, fontFace: FONT_B, fontSize: 14.5, color: MUTED, lineSpacingMultiple: 1.1, margin: 0, valign: "top" });
  s.addText("OUR MRR", { x: x + 0.35, y: 5.55, w: 2.95, h: 0.28, fontFace: FONT_B, fontSize: 10, bold: true, color: MUTED, charSpacing: 2, margin: 0 });
  s.addText(mrr, { x: x + 0.35, y: 5.78, w: 2.95, h: 0.55, fontFace: FONT_H, fontSize: 30, bold: true, color: col, margin: 0 });
});
s.addText("Difficulty increases left → right.  One generic matcher wouldn't win — so we built one per regime.", { x: 0.6, y: 6.7, w: 12.1, h: 0.4, fontFace: FONT_B, fontSize: 14, italic: true, color: MUTED, align: "center", margin: 0 });

// ============================================================
// Slide 4 — Key insight: MIND descriptors
// ============================================================
s = pres.addSlide();
s.background = { color: NAVY };
s.addShape(pres.shapes.OVAL, { x: 10.2, y: 4.3, w: 5.0, h: 5.0, fill: { color: TEAL, transparency: 90 }, line: { type: "none" } });
s.addText("THE KEY INSIGHT", { x: 0.7, y: 0.7, w: 11, h: 0.3, fontFace: FONT_B, fontSize: 13, bold: true, color: MINT, charSpacing: 3, margin: 0 });
s.addText("MIND descriptors make modality irrelevant", { x: 0.7, y: 1.05, w: 12, h: 0.8, fontFace: FONT_H, fontSize: 30, bold: true, color: "FFFFFF", margin: 0 });

s.addText([
  { text: "MIND", options: { bold: true, color: MINT } },
  { text: " (Modality-Independent Neighbourhood Descriptor) encodes each voxel by the ", options: {} },
  { text: "local self-similarity of its surroundings", options: { bold: true } },
  { text: " — the texture pattern, not the intensity.", options: {} },
], { x: 0.7, y: 2.15, w: 6.7, h: 1.6, fontFace: FONT_B, fontSize: 18, color: "D7E6EC", lineSpacingMultiple: 1.18, margin: 0 });

const pts = [
  "Intensities differ between ceT1 and T2 — but the structure around each voxel doesn't.",
  "So the same anatomy yields the same descriptor field across both contrasts.",
  "Zero training, zero labels — it bridges the modality gap by construction.",
];
let py = 3.95;
pts.forEach((p) => {
  s.addShape(pres.shapes.OVAL, { x: 0.7, y: py + 0.05, w: 0.16, h: 0.16, fill: { color: TEAL }, line: { type: "none" } });
  s.addText(p, { x: 1.05, y: py - 0.1, w: 6.3, h: 0.7, fontFace: FONT_B, fontSize: 15, color: "C9DCE5", margin: 0, valign: "top", lineSpacingMultiple: 1.05 });
  py += 0.85;
});

// right: equation-style card
s.addShape(pres.shapes.ROUNDED_RECTANGLE, { x: 8.0, y: 2.3, w: 4.75, h: 3.95, fill: { color: NAVY2 }, line: { color: TEAL, width: 1 }, rectRadius: 0.1, shadow: shadow() });
s.addText("WHY IT WORKS", { x: 8.35, y: 2.6, w: 4.1, h: 0.3, fontFace: FONT_B, fontSize: 11, bold: true, color: MINT, charSpacing: 2, margin: 0 });
s.addText([
  { text: "ceT1 voxel", options: { color: "9FB8C4", breakLine: true } },
  { text: "intensity  ≠  T2 intensity", options: { color: "EF8E8E", bold: true, breakLine: true } },
  { text: "", options: { breakLine: true } },
  { text: "MIND(ceT1)", options: { color: "9FB8C4", breakLine: true } },
  { text: "≈  MIND(T2)", options: { color: MINT, bold: true } },
], { x: 8.35, y: 3.1, w: 4.1, h: 1.7, fontFace: "Consolas", fontSize: 20, margin: 0, lineSpacingMultiple: 1.05 });
s.addText("Correlate the two descriptor fields → a same-patient similarity score that ignores contrast.", { x: 8.35, y: 5.15, w: 4.1, h: 1.0, fontFace: FONT_B, fontSize: 14, italic: true, color: "C9DCE5", margin: 0, lineSpacingMultiple: 1.1 });

// ============================================================
// Slide 5 — Pipeline: one matcher per regime
// ============================================================
s = pres.addSlide();
header(s, "Our approach", "A specialised matcher for each regime");

const flow = [
  ["D1 · Aligned", "Dense MIND", "Correlate MIND fields voxel-by-voxel on the shared grid.", TEAL],
  ["D2 · Deformed", "Register → Dense MIND", "Align each volume to a canonical pose (GPU, MIND-driven), then match.", AMBER],
  ["D3 · Pre→intra-op", "Shape prior + MIND", "Match on original-array shape, tie-break with global MIND.", "EF6C6C"],
];
let fy = 1.95;
flow.forEach(([reg, method, desc, col]) => {
  s.addShape(pres.shapes.ROUNDED_RECTANGLE, { x: 0.6, y: fy, w: 2.55, h: 1.35, fill: { color: col }, line: { type: "none" }, rectRadius: 0.08, shadow: shadow() });
  s.addText(reg, { x: 0.6, y: fy + 0.18, w: 2.55, h: 0.4, fontFace: FONT_B, fontSize: 13, bold: true, color: "FFFFFF", align: "center", margin: 0 });
  s.addText(method, { x: 0.6, y: fy + 0.6, w: 2.55, h: 0.6, fontFace: FONT_H, fontSize: 16, bold: true, color: "FFFFFF", align: "center", margin: 0, valign: "top" });
  // arrow
  s.addShape(pres.shapes.RIGHT_TRIANGLE, { x: 3.32, y: fy + 0.5, w: 0.34, h: 0.34, fill: { color: MUTED }, line: { type: "none" }, rotate: 0 });
  s.addText(desc, { x: 3.95, y: fy + 0.05, w: 8.7, h: 1.3, fontFace: FONT_B, fontSize: 16, color: INK, valign: "middle", margin: 0, lineSpacingMultiple: 1.05 });
  fy += 1.55;
});
s.addShape(pres.shapes.ROUNDED_RECTANGLE, { x: 0.6, y: 6.7, w: 12.1, h: 0.55, fill: { color: "EAF6F4" }, line: { type: "none" }, rectRadius: 0.06 });
s.addText([
  { text: "All on GPU, all classical — ", options: { bold: true, color: INK } },
  { text: "no learned weights to train, deploy, or overfit. Fully reproducible from one script.", options: { color: MUTED } },
], { x: 0.8, y: 6.7, w: 11.8, h: 0.55, fontFace: FONT_B, fontSize: 13.5, valign: "middle", margin: 0 });

// ============================================================
// Slide 6 — The D2 unlock (registration)
// ============================================================
s = pres.addSlide();
header(s, "The breakthrough", "Unlocking D2 by undoing the deformation");
s.addText([
  { text: "D2 is just D1 with each volume independently moved and warped. ", options: { color: INK } },
  { text: "So we register every volume back to a canonical pose", options: { bold: true, color: TEAL } },
  { text: " — a rigid + scale transform optimised on the GPU using the modality-invariant MIND similarity itself — then run the D1 matcher.", options: { color: INK } },
], { x: 0.6, y: 1.75, w: 7.0, h: 2.0, fontFace: FONT_B, fontSize: 17, lineSpacingMultiple: 1.15, margin: 0 });

s.addText("~70 Adam iterations per volume.  No labels, no template learning — a clean sample of D1 galleries is the reference.", { x: 0.6, y: 3.85, w: 7.0, h: 0.8, fontFace: FONT_B, fontSize: 14, italic: true, color: MUTED, margin: 0, lineSpacingMultiple: 1.1 });

// before/after big stat
s.addShape(pres.shapes.ROUNDED_RECTANGLE, { x: 0.6, y: 4.95, w: 3.35, h: 1.7, fill: { color: CARD }, line: { color: "E3EAEE", width: 1 }, rectRadius: 0.08, shadow: shadow() });
s.addText("BEFORE", { x: 0.6, y: 5.15, w: 3.35, h: 0.3, fontFace: FONT_B, fontSize: 11, bold: true, color: MUTED, charSpacing: 2, align: "center", margin: 0 });
s.addText("0.15", { x: 0.6, y: 5.45, w: 3.35, h: 0.9, fontFace: FONT_H, fontSize: 46, bold: true, color: "EF6C6C", align: "center", margin: 0 });

s.addShape(pres.shapes.RIGHT_TRIANGLE, { x: 4.12, y: 5.65, w: 0.4, h: 0.4, fill: { color: TEAL }, line: { type: "none" } });

s.addShape(pres.shapes.ROUNDED_RECTANGLE, { x: 4.7, y: 4.95, w: 3.35, h: 1.7, fill: { color: NAVY }, line: { type: "none" }, rectRadius: 0.08, shadow: shadow() });
s.addText("AFTER (proxy D2)", { x: 4.7, y: 5.15, w: 3.35, h: 0.3, fontFace: FONT_B, fontSize: 11, bold: true, color: "9FB8C4", charSpacing: 2, align: "center", margin: 0 });
s.addText("0.72", { x: 4.7, y: 5.45, w: 3.35, h: 0.9, fontFace: FONT_H, fontSize: 46, bold: true, color: MINT, align: "center", margin: 0 });

// right panel: impact
s.addShape(pres.shapes.ROUNDED_RECTANGLE, { x: 8.3, y: 1.75, w: 4.45, h: 4.9, fill: { color: NAVY }, line: { type: "none" }, rectRadius: 0.1, shadow: shadow() });
s.addText("4.7×", { x: 8.5, y: 2.15, w: 4.05, h: 1.1, fontFace: FONT_H, fontSize: 64, bold: true, color: MINT, align: "center", margin: 0 });
s.addText("improvement on the D2 proxy", { x: 8.5, y: 3.25, w: 4.05, h: 0.4, fontFace: FONT_B, fontSize: 15, color: "C9DCE5", align: "center", margin: 0 });
s.addShape(pres.shapes.LINE, { x: 9.0, y: 4.0, w: 3.05, h: 0, line: { color: "2C4A5A", width: 1 } });
s.addText([
  { text: "And the macro score moved with it:", options: { color: "9FB8C4", breakLine: true, fontSize: 14 } },
  { text: "0.61  →  0.703", options: { color: MINT, bold: true, fontSize: 26 } },
], { x: 8.5, y: 4.25, w: 4.05, h: 1.4, fontFace: FONT_H, align: "center", margin: 0, lineSpacingMultiple: 1.3 });
s.addText("D2 was the bottleneck. This was the single biggest lever.", { x: 8.5, y: 5.85, w: 4.05, h: 0.7, fontFace: FONT_B, fontSize: 13, italic: true, color: "C9DCE5", align: "center", margin: 0, lineSpacingMultiple: 1.05 });

// ============================================================
// Slide 7 — Results
// ============================================================
s = pres.addSlide();
header(s, "Results", "0.455 → 0.703 macro MRR");

// per-dataset bar chart
s.addChart(pres.charts.BAR, [
  { name: "MRR", labels: ["D1 · Aligned", "D2 · Deformed", "D3 · Pre→intra-op", "MACRO"], values: [0.72, 0.60, 0.85, 0.703] },
], {
  x: 0.5, y: 1.95, w: 7.2, h: 4.7, barDir: "col",
  chartColors: [TEAL, AMBER, "EF6C6C", "0E2A3B"],
  valAxisMinVal: 0, valAxisMaxVal: 1.0,
  showValue: true, dataLabelPosition: "outEnd", dataLabelColor: INK, dataLabelFontSize: 14, dataLabelFontBold: true,
  catAxisLabelColor: MUTED, catAxisLabelFontSize: 12, catAxisLabelFontBold: true,
  valAxisLabelColor: MUTED, valAxisLabelFontSize: 10,
  valGridLine: { color: "E2E8F0", size: 0.5 }, catGridLine: { style: "none" },
  showLegend: false, showTitle: false,
  chartArea: { fill: { color: LIGHT } }, plotArea: { fill: { color: LIGHT } },
});

// right: journey + headline
s.addShape(pres.shapes.ROUNDED_RECTANGLE, { x: 8.15, y: 1.95, w: 4.6, h: 2.1, fill: { color: NAVY }, line: { type: "none" }, rectRadius: 0.1, shadow: shadow() });
s.addText("+55%", { x: 8.15, y: 2.15, w: 4.6, h: 0.9, fontFace: FONT_H, fontSize: 50, bold: true, color: MINT, align: "center", margin: 0 });
s.addText("relative gain over the baseline", { x: 8.15, y: 3.1, w: 4.6, h: 0.4, fontFace: FONT_B, fontSize: 15, color: "C9DCE5", align: "center", margin: 0 });
s.addText("0.455  →  0.703", { x: 8.15, y: 3.5, w: 4.6, h: 0.45, fontFace: FONT_H, fontSize: 20, bold: true, color: "FFFFFF", align: "center", margin: 0 });

s.addText("THE JOURNEY", { x: 8.3, y: 4.35, w: 4.3, h: 0.3, fontFace: FONT_B, fontSize: 11, bold: true, color: TEAL, charSpacing: 2, margin: 0 });
const journey = [
  ["0.455", "Provided baseline"],
  ["0.61", "Per-dataset classical blend + shape prior"],
  ["0.703", "+ D2 canonical-pose registration"],
];
let jy = 4.7;
journey.forEach(([v, d], i) => {
  const col = i === 2 ? TEAL : MUTED;
  s.addText(v, { x: 8.3, y: jy, w: 1.25, h: 0.5, fontFace: FONT_H, fontSize: 20, bold: true, color: col, margin: 0 });
  s.addText(d, { x: 9.6, y: jy + 0.03, w: 3.1, h: 0.55, fontFace: FONT_B, fontSize: 12.5, color: INK, valign: "middle", margin: 0, lineSpacingMultiple: 1.0 });
  jy += 0.62;
});

// ============================================================
// Slide 8 — What we tried & rejected (rigor)
// ============================================================
s = pres.addSlide();
header(s, "Scientific rigor", "We chased the leaks — and ruled them out");
const rej = [
  ["Identity leak via BraTS", "D1/D2 are BraTS-format, so we downloaded BraTS-2021 (1,251 patients) and matched. Best similarity ~0.45 vs ~0.95 for a true match — the patients simply aren't there. Leak is dead.", "Tested, rejected"],
  ["Learned contrastive 3D CNN", "A CLIP-style embedder on MIND inputs scored 0.17 macro on the proxy — worse than classical everywhere. 350 labelled pairs is far too few for a global 3D network.", "Tested, rejected"],
];
let ry = 1.95;
rej.forEach(([t, d, tag]) => {
  s.addShape(pres.shapes.ROUNDED_RECTANGLE, { x: 0.6, y: ry, w: 12.1, h: 1.85, fill: { color: CARD }, line: { color: "E3EAEE", width: 1 }, rectRadius: 0.08, shadow: shadow() });
  s.addText("✕", { x: 0.9, y: ry + 0.3, w: 0.7, h: 0.7, fontFace: FONT_B, fontSize: 30, bold: true, color: "EF6C6C", align: "center", valign: "middle", margin: 0 });
  s.addText(t, { x: 1.75, y: ry + 0.22, w: 8.0, h: 0.45, fontFace: FONT_H, fontSize: 19, bold: true, color: INK, margin: 0 });
  s.addText(d, { x: 1.75, y: ry + 0.68, w: 9.0, h: 1.05, fontFace: FONT_B, fontSize: 14, color: MUTED, margin: 0, lineSpacingMultiple: 1.08, valign: "top" });
  s.addShape(pres.shapes.ROUNDED_RECTANGLE, { x: 10.95, y: ry + 0.28, w: 1.55, h: 0.42, fill: { color: "FBE9E9" }, line: { type: "none" }, rectRadius: 0.2 });
  s.addText(tag.toUpperCase(), { x: 10.95, y: ry + 0.28, w: 1.55, h: 0.42, fontFace: FONT_B, fontSize: 9.5, bold: true, color: "C2453F", align: "center", valign: "middle", charSpacing: 1, margin: 0 });
  ry += 2.1;
});
s.addText([
  { text: "Negative results are results. ", options: { bold: true, color: TEAL } },
  { text: "Documenting the dead ends is why the surviving pipeline is trustworthy — and honest about its ceiling.", options: { color: MUTED } },
], { x: 0.6, y: 6.35, w: 12.1, h: 0.7, fontFace: FONT_B, fontSize: 14.5, italic: true, align: "center", margin: 0 });

// ============================================================
// Slide 9 — Closing / demo / next
// ============================================================
s = pres.addSlide();
s.background = { color: NAVY };
s.addShape(pres.shapes.OVAL, { x: 9.9, y: 3.9, w: 5.6, h: 5.6, fill: { color: TEAL, transparency: 88 }, line: { type: "none" } });
s.addShape(pres.shapes.OVAL, { x: -1.8, y: -2.0, w: 4.8, h: 4.8, fill: { color: MINT, transparency: 91 }, line: { type: "none" } });

s.addText("TAKEAWAY", { x: 0.7, y: 0.85, w: 11, h: 0.3, fontFace: FONT_B, fontSize: 13, bold: true, color: MINT, charSpacing: 3, margin: 0 });
s.addText("Classical descriptors, used well,\nbeat learning here", { x: 0.7, y: 1.3, w: 11.5, h: 1.7, fontFace: FONT_H, fontSize: 38, bold: true, color: "FFFFFF", lineSpacingMultiple: 1.0, margin: 0 });

const take = [
  ["MIND bridges the modality gap", "with no training and no labels."],
  ["A matcher per regime + GPU registration", "took macro MRR from 0.455 to 0.703."],
  ["Reproducible in one command", "make_submission_best.py — fully transparent."],
];
let ty = 3.5;
take.forEach(([a, b]) => {
  s.addShape(pres.shapes.OVAL, { x: 0.72, y: ty + 0.06, w: 0.2, h: 0.2, fill: { color: TEAL }, line: { type: "none" } });
  s.addText([
    { text: a + "  ", options: { bold: true, color: "FFFFFF" } },
    { text: b, options: { color: "C9DCE5" } },
  ], { x: 1.1, y: ty - 0.1, w: 8.4, h: 0.55, fontFace: FONT_B, fontSize: 16.5, margin: 0, valign: "top" });
  ty += 0.72;
});

s.addShape(pres.shapes.ROUNDED_RECTANGLE, { x: 0.7, y: 6.05, w: 6.7, h: 0.95, fill: { color: NAVY2 }, line: { color: TEAL, width: 1 }, rectRadius: 0.1 });
s.addText([
  { text: "Live demo + code:  ", options: { bold: true, color: MINT } },
  { text: "ceT1 query → ranked T2 gallery, top-1 retrieved.", options: { color: "D7E6EC" } },
], { x: 0.95, y: 6.05, w: 6.2, h: 0.95, fontFace: FONT_B, fontSize: 14, valign: "middle", margin: 0 });

s.addText("Thank you — questions welcome.", { x: 7.7, y: 6.05, w: 5.0, h: 0.95, fontFace: FONT_H, fontSize: 18, italic: true, bold: true, color: "FFFFFF", align: "right", valign: "middle", margin: 0 });

// ---- speaker notes ----
pres.slides[0].addNotes("Open: we tackled the Inria cross-modal retrieval challenge. One line: match the same patient across MRI contrasts, no training, no labels. We hit 0.703 macro MRR, up from the 0.455 baseline. Pause on the number.");
pres.slides[1].addNotes("Frame the task precisely — it's retrieval, not tumor classification. Query is a contrast-T1, we rank a gallery of T2s, same patient must be rank 1. Three reasons it's hard: contrast looks totally different (point at image), geometry differs, and the patients are unseen so no learning shortcut. Metric is MRR averaged over 3 datasets.");
pres.slides[2].addNotes("Three regimes of rising difficulty. D1 aligned — easy, shared grid. D2 same data but deformed — geometry breaks naive matching. D3 pre vs intra-op — anatomy literally changes (resection), shape becomes the signal. Key decision: one matcher per regime, not one generic model.");
pres.slides[3].addNotes("The conceptual core. MIND describes each voxel by the self-similarity of its neighbourhood — texture, not intensity. Intensities differ between ceT1 and T2; local structure doesn't. So MIND(ceT1) ≈ MIND(T2) for the same anatomy. We correlate the descriptor fields. No training at all — this is what makes cross-modal work.");
pres.slides[4].addNotes("How MIND plugs into each regime. D1: dense voxel-wise MIND correlation on the shared grid. D2: register to canonical pose first, then D1 matcher. D3: original-array shape prior with a global-MIND tie-break. Everything classical and GPU — nothing to train or overfit, reproducible from one script.");
pres.slides[5].addNotes("The breakthrough slide — spend time here. D2 is just D1 moved and warped, so we undo it: optimise a rigid+scale transform on GPU using MIND similarity itself as the objective, ~70 Adam iters, then match. Proxy D2 went 0.15 to 0.72 — 4.7x. That dragged the macro from 0.61 to 0.703. D2 was the bottleneck; this was the single biggest lever.");
pres.slides[6].addNotes("Results. Per-dataset: D1 0.72, D2 ~0.60, D3 0.85, macro 0.703. The journey: baseline 0.455, classical blend got us to 0.61, the D2 registration pushed to 0.703 — 55% relative gain. Be honest that D2 still has the most headroom.");
pres.slides[7].addNotes("Rigor and honesty. We aggressively chased leaks. Downloaded the full BraTS-2021 set to test an identity leak — the patients aren't in it, dead. Tried a learned contrastive CNN — 0.17, worse than classical, too few labels. Showing what failed is why the pipeline that survived is trustworthy.");
pres.slides[8].addNotes("Close. The lesson: classical descriptors used well beat learning in this low-data, cross-modal regime. MIND + per-regime matching + GPU registration = 0.455 to 0.703, reproducible in one command. Offer the live demo: pick a ceT1 query, show the ranked T2 gallery and the correct top-1. Thank you.");

pres.writeFile({ fileName: "deck.pptx" }).then((f) => console.log("WROTE " + f));

